// src/components/CouponForm/index.jsx

import React, { useState } from 'react';
import { useForm } from 'react-hook-form';
import { BASE_URL } from '../../utils/api'; 
// Импортируем локальные стили, которые будут содержать submittedButton
import s from './CouponForm.module.css'; 

// Меняем s на formClassName, чтобы избежать конфликта
const CouponForm = ({ formClassName }) => { 
  // Локальное состояние: Отслеживание успешной отправки
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [isError, setIsError] = useState(false);

  const { 
    register, 
    handleSubmit, 
    formState: { errors },
    reset 
  } = useForm();

  const onSubmit = async (data) => {
    if (isSubmitted) return;

    setIsError(false);

    try {
      const response = await fetch(`${BASE_URL}/sale/send`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ 
            name: data.name, 
            phone: data.phone,
            email: data.email 
        }),
      });

      if (response.ok) {
        setIsSubmitted(true); 
        reset(); 
      } else {
        setIsError(true);
        console.error('Ошибка при отправке заявки:', response.status);
      }
    } catch (error) {
      setIsError(true);
      console.error('Ошибка сети:', error);
    }
  };

  const buttonText = isSubmitted ? 'Request Submitted' : 'Get a discount';
  // 🔑 Теперь submittedButton берется из локального импорта 's'
  const buttonClass = isSubmitted ? s.submittedButton : '';

  return (
    // Применяем внешний класс для всей формы
    <form onSubmit={handleSubmit(onSubmit)} className={formClassName}>

        {/* Инпуты остаются без изменений */}
        <input
            type="text"
            placeholder="Name"
            {...register('name', { required: 'Введите имя' })}
        />

        <input
            type="tel"
            placeholder="Phone number"
            {...register('phone', { required: 'Введите номер телефона' })}
        />

        <input
            type="email"
            placeholder="Email"
            {...register('email', { required: 'Введите email' })}
        />

        {/* Кнопка */}
        <button 
            type="submit"
            className={buttonClass} 
            disabled={isSubmitted}     
        >
          {buttonText}
        </button>

        {/* Ошибки, если нужно, тоже берем из локальных стилей s */}
        {isError && <p className={s.formError}>An error occurred during submission.</p>}

    </form>
  );
};

export default CouponForm;
